console.log(`📋 ${quellen.length} Quellen werden in Notion eingetragen (DB: ${dbId})`);
return quellen.map(q => ({ json: { ...q, dbId } }));

const items = $input.all();
const erfolg = items.filter(i => i.json.object === 'page').length;
const fehler = items.length - erfolg;

if (fehler > 0) {
  const fehlerliste = items
    .filter(i => i.json.object !== 'page')
    .map(i => i.json.message || JSON.stringify(i.json).substring(0, 100));
  console.log(`⚠️ ${fehler} Fehler:`, fehlerliste);
  console.log('Häufige Ursache: Spaltenname in Notion stimmt nicht überein.');
  console.log('Erwartete Spalten: Name (Title), URL (URL), Kategorie (Select), Aktiv (Checkbox), Notiz (Text)');
}

console.log(`✅ ${erfolg} von ${items.length} Quellen erfolgreich eingetragen`);

return [{
  json: {
    status: erfolg === items.length ? 'Vollständig erfolgreich' : `${fehler} Fehler aufgetreten`,
    eingetragen: erfolg,
    fehler: fehler,
    notionDbId: '36b47c762802803f8311ce87bcce27a5',
    naechsterSchritt: fehler > 0
      ? 'Prüfe die Spaltenbezeichnungen in deiner Notion-Datenbank (siehe Hinweis im Node)'
      : 'Setup abgeschlossen! Die DB-ID ist bereits im Hauptworkflow eingetragen.'
  }
}];
